import React, { useState, useEffect, useRef } from "react";
import PageLayout from "../../Layout/PageLayout";
import "./vidya.css";

// ── 🔑 Google Gemini API Key ──────────────────────────────────────────────
// Get your FREE key at: https://aistudio.google.com/app/apikey
const GEMINI_API_KEY = "YOUR_GEMINI_API_KEY_HERE";
const GEMINI_MODEL   = "gemini-2.0-flash";
const GEMINI_URL     = `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent?key=${GEMINI_API_KEY}`;

// ── Teacher data ──────────────────────────────────────────────────────────
const TEACHERS = {
  priya: {
    id: "priya", name: "Dr. Priya", fullName: "Dr. Priya Sharma",
    role: "Biology Expert · NEET", exam: "NEET UG",
    color: "#3fb950", colorRGB: "63,185,80",
    examBg: "rgba(63,185,80,0.1)", examBorder: "rgba(63,185,80,0.3)",
    icon: "🧬", subjects: ["Botany", "Zoology", "Human Physiology"],
    pitch: 1.05, rate: 0.80,
    quickTopics: [
      "Explain cell division step by step",
      "Difference between mitosis and meiosis?",
      "How does the human digestive system work?",
      "Most important NEET Biology chapters?",
    ],
    system: `You are Dr. Priya Sharma, a highly experienced Biology teacher for NEET UG in India. You teach Botany, Zoology, and Human Physiology from NCERT Class 11 and 12. Explain every concept step by step in simple, clear Indian English that Class 11 and 12 students can easily understand. Always mention the relevant NCERT chapter. Use helpful mnemonics and simple analogies. Be warm, patient, and encouraging. Do not use markdown — write in plain spoken sentences suitable for voice reading.`,
    greeting: "Namaste! I am Dr. Priya Sharma, your Biology teacher for NEET. Whether it is Botany, Zoology, or Human Physiology, I will make every concept very clear using NCERT. What topic would you like to study today?",
    svg: `<svg viewBox="0 0 140 210" xmlns="http://www.w3.org/2000/svg" style="width:128px;height:198px"><path d="M32 118 Q70 108 108 118 L102 200 L38 200 Z" fill="#1a3a2a"/><path d="M32 118 Q70 108 108 118 L110 135 Q70 144 30 135 Z" fill="#3fb950" opacity="0.55"/><path d="M38 118 Q20 152 24 186" stroke="#3fb950" stroke-width="8" fill="none" stroke-linecap="round" opacity="0.6"/><rect x="62" y="107" width="16" height="14" rx="4" fill="#c68a5e"/><ellipse cx="70" cy="78" rx="28" ry="31" fill="#c68a5e"/><ellipse cx="70" cy="50" rx="26" ry="13" fill="#1a0a00"/><ellipse cx="70" cy="44" rx="14" ry="10" fill="#1a0a00"/><circle cx="70" cy="58" r="3" fill="#e8335a"/><circle cx="70" cy="66" r="2.5" fill="#e8335a"/><rect x="51" y="73" width="15" height="11" rx="5" fill="none" stroke="#3fb950" stroke-width="1.8"/><rect x="74" y="73" width="15" height="11" rx="5" fill="none" stroke="#3fb950" stroke-width="1.8"/><line x1="66" y1="78" x2="74" y2="78" stroke="#3fb950" stroke-width="1.8"/><ellipse cx="58" cy="78" rx="3" ry="3.5" fill="#1a0a00"/><ellipse cx="81" cy="78" rx="3" ry="3.5" fill="#1a0a00"/><circle cx="59.5" cy="76.5" r="1" fill="white"/><circle cx="82.5" cy="76.5" r="1" fill="white"/><path d="M52 70 Q58 67 64 70" stroke="#1a0a00" stroke-width="1.6" fill="none"/><path d="M76 70 Q82 67 88 70" stroke="#1a0a00" stroke-width="1.6" fill="none"/><path d="M68 88 Q70 91 72 88" stroke="#a0725a" stroke-width="1.2" fill="none"/><path id="mouth" d="M64 96 Q70 101 76 96" stroke="#a05040" stroke-width="2" fill="none" stroke-linecap="round"/><ellipse cx="42" cy="80" rx="5" ry="7" fill="#c68a5e"/><ellipse cx="98" cy="80" rx="5" ry="7" fill="#c68a5e"/><circle cx="42" cy="87" r="3" fill="#f7a325"/><circle cx="98" cy="87" r="3" fill="#f7a325"/><rect x="88" y="148" width="24" height="32" rx="3" fill="#1a6b2a" stroke="#3fb950" stroke-width="1.5"/><line x1="100" y1="151" x2="100" y2="177" stroke="#3fb950" stroke-width="1"/><path d="M108 130 Q120 145 112 163" stroke="#1a3a2a" stroke-width="12" fill="none" stroke-linecap="round"/></svg>`,
  },
  arjun: {
    id: "arjun", name: "Prof. Arjun", fullName: "Prof. Arjun Verma",
    role: "Physics Expert · JEE", exam: "JEE Mains & Adv",
    color: "#388bfd", colorRGB: "56,139,253",
    examBg: "rgba(56,139,253,0.1)", examBorder: "rgba(56,139,253,0.3)",
    icon: "⚛️", subjects: ["Mechanics", "Electrodynamics", "Modern Physics"],
    pitch: 0.88, rate: 0.78,
    quickTopics: [
      "Explain Newton's laws with JEE examples",
      "Tricks for solving circuit problems?",
      "Important JEE Physics formulas",
      "How to approach JEE Advanced problems?",
    ],
    system: `You are Prof. Arjun Verma, an expert Physics teacher for JEE Mains and JEE Advanced in India with 15 years of experience. You teach Mechanics, Electrodynamics, Optics, and Modern Physics. Explain problems step by step with clear logic. Give important formulas and JEE tricks. Reference HC Verma and DC Pandey when helpful. Build strong conceptual foundations. Speak in simple, clear Indian English. Do not use markdown — write in plain spoken sentences.`,
    greeting: "Hello! I am Prof. Arjun Verma, your Physics guide for JEE Mains and Advanced. Physics is about understanding logic, not just memorizing formulas. We will build a strong foundation together. Which topic or problem shall we start with today?",
