// ── Component ──────────────────────────────────────────────────────────────
export default function VIDYAPage({ userName }) {
  const [current, setCurrent] = useState(TEACHERS.priya);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [busy, setBusy] = useState(false);
  const [autoVoice, setAutoVoice] = useState(false);
  const [chatHistory, setChatHistory] = useState([]);
  const [apiKeyInput, setApiKeyInput] = useState("");
  const [apiKey, setApiKey] = useState(
    GEMINI_API_KEY !== "YOUR_GEMINI_API_KEY_HERE" ? GEMINI_API_KEY : (localStorage.getItem("vidya_gemini_key") || "")
  );
  const [showKeyPrompt, setShowKeyPrompt] = useState(false);
  const chatboxRef = useRef(null);
  const mouthIntervalRef = useRef(null);
  const inputRef = useRef(null);

  useEffect(() => {
    if (chatboxRef.current)
      chatboxRef.current.scrollTop = chatboxRef.current.scrollHeight;
  }, [messages]);

  useEffect(() => { selectTeacher("priya"); }, []); // eslint-disable-line

  // Show key prompt if no key set
  useEffect(() => {
    if (!apiKey) setShowKeyPrompt(true);
    else setShowKeyPrompt(false);
  }, [apiKey]);

  function saveApiKey() {
    const k = apiKeyInput.trim();
    if (!k) return;
    localStorage.setItem("vidya_gemini_key", k);
    setApiKey(k);
    setApiKeyInput("");
  }

  function selectTeacher(id) {
    const t = TEACHERS[id];
    setCurrent(t);
    setChatHistory([]);
    setMessages([{ role: "greeting", text: t.greeting, id: Date.now() }]);
    stopMouth();
    if (window.speechSynthesis) window.speechSynthesis.cancel();
  }

  // ── Voice ──
  function getBestVoice(t) {
    const voices = window.speechSynthesis?.getVoices() || [];
    const male = t.id === "arjun" || t.id === "ravi";
    const en = voices.filter(v => /en/i.test(v.lang));
    if (male) return en.find(v => /male/i.test(v.name)) || en[0] || voices[0];
    return en.find(v => /female/i.test(v.name)) || en[0] || voices[0];
  }

  function speak(text, t) {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    const clean = text.replace(/[*_#`]/g, "").replace(/\n+/g, ". ");
    const u = new SpeechSynthesisUtterance(clean);
    u.pitch = t.pitch; u.rate = t.rate; u.volume = 1;
    const v = getBestVoice(t); if (v) u.voice = v;
    u.onstart = startMouth;
    u.onend = stopMouth;
    u.onerror = stopMouth;
    window.speechSynthesis.speak(u);
  }

  function startMouth() {
    const ring = document.getElementById("vidya-pulse-ring");
    if (ring) ring.classList.add("pulsing");
    clearInterval(mouthIntervalRef.current);
    mouthIntervalRef.current = setInterval(() => {
      const m = document.getElementById("mouth");
      if (!m) return;
      const y = 97 + Math.random() * 9;
      m.setAttribute("d", `M64 96 Q70 ${y} 76 96`);
    }, 120);
  }

  function stopMouth() {
    clearInterval(mouthIntervalRef.current);
    const ring = document.getElementById("vidya-pulse-ring");
    if (ring) ring.classList.remove("pulsing");
    const m = document.getElementById("mouth");
    if (m) m.setAttribute("d", "M64 96 Q70 100 76 96");
  }

  // ── Send via Google Gemini ──
  async function sendMessage(overrideText) {
    if (busy) return;
    const text = (overrideText || input).trim();
    if (!text) return;

    if (!apiKey) { setShowKeyPrompt(true); return; }

    setInput("");
    const userMsg = { role: "user", text, id: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setBusy(true);

    try {
      // Build Gemini-format conversation history
      const contents = [
        // System instruction as first user turn (Gemini supports systemInstruction separately)
        ...chatHistory,
        { role: "user", parts: [{ text }] },
      ];

      const res = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent?key=${apiKey}`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            systemInstruction: {
              parts: [{ text: current.system }]
            },
            contents,
            generationConfig: {
              maxOutputTokens: 1024,
              temperature: 0.7,
            },
          }),
        }
      );

      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        const msg = err?.error?.message || `API error ${res.status}`;
        // If key is invalid, prompt to re-enter
        if (res.status === 400 || res.status === 403) {
          setShowKeyPrompt(true);
          setApiKey("");
          localStorage.removeItem("vidya_gemini_key");
        }
        throw new Error(msg);
      }

      const data = await res.json();
      const reply =
        data?.candidates?.[0]?.content?.parts?.[0]?.text ||
        "Sorry, I could not process that. Please try again.";

      const newHistory = [
        ...chatHistory,
        { role: "user", parts: [{ text }] },
        { role: "model", parts: [{ text: reply }] },
      ];
      setChatHistory(newHistory.slice(-20));
      setMessages(prev => [...prev, { role: "bot", text: reply, id: Date.now() }]);
      if (autoVoice) speak(reply, current);
    } catch (e) {
      setMessages(prev => [...prev, {
        role: "bot",
        text: `⚠️ ${e.message || "Connection issue. Please check your internet and try again."}`,
        id: Date.now()
      }]);
    }

    setBusy(false);
    inputRef.current?.focus();
  }

  const accentStyle = {
    "--vidya-accent": current.color,
    "--vidya-accent-rgb": current.colorRGB,
  };

  return (
    <PageLayout userName={userName}>
      <div className="vidya-root" style={accentStyle}>

        {/* ── API Key Setup Prompt ── */}
        {showKeyPrompt && (
          <div className="vidya-key-overlay">
            <div className="vidya-key-modal">
              <div className="vidya-key-icon">🔑</div>
              <h2>Enter your Gemini API Key</h2>
              <p>
                VIDYA AI uses Google Gemini (free). Get your free key from{" "}
                <a href="https://aistudio.google.com/app/apikey" target="_blank" rel="noreferrer">
                  Google AI Studio
                </a>{" "}
                — it takes under a minute.
              </p>
              <input
                className="vidya-key-input"
                type="password"
                placeholder="Paste your Gemini API key here…"
                value={apiKeyInput}
                onChange={e => setApiKeyInput(e.target.value)}
                onKeyDown={e => { if (e.key === "Enter") saveApiKey(); }}
                autoFocus
              />
              <button className="vidya-key-btn" onClick={saveApiKey}
                style={{ background: `linear-gradient(135deg,${current.color},${current.color}bb)` }}>
                Save & Start Chatting →
              </button>
              <p className="vidya-key-note">Your key is saved locally in your browser only.</p>
            </div>
          </div>
        )}

        {/* ── Sidebar ── */}
        <aside className="vidya-sidebar">
          <div className="vidya-sidebar-top">

            {/* Brand */}
            <div className="vidya-brand">
              <div className="vidya-brand-icon" style={{ background: `linear-gradient(135deg,${current.color},${current.color}aa)` }}>🎓</div>
              <div>
                <div className="vidya-brand-text">VidyaBot</div>
                <div className="vidya-brand-sub">AI Exam Tutor · Gemini</div>
              </div>
            </div>

            {/* Exam badges */}
            <div className="vidya-exam-row">
              <span className="vidya-badge badge-neet">NEET</span>
              <span className="vidya-badge badge-jeem">JEE Mains</span>
              <span className="vidya-badge badge-jeea">JEE Adv</span>
              <span className="vidya-badge badge-board">Boards</span>
            </div>

            {/* Avatar stage */}
            <div className="vidya-avatar-stage">
              <div className="vidya-stage-bg"
                style={{ background: `radial-gradient(ellipse at 50% 110%, rgba(${current.colorRGB},0.17) 0%, transparent 65%)` }} />
              <div className="vidya-stage-glow" style={{ background: `rgba(${current.colorRGB},0.25)` }} />
              <div className="vidya-pulse-ring" id="vidya-pulse-ring" style={{ borderColor: current.color }} />
              <div className="vidya-avatar-wrap"
                dangerouslySetInnerHTML={{ __html: current.svg }} />
            </div>

            {/* Teacher info */}
            <div className="vidya-teacher-info">
              <h2>{current.name}</h2>
              <span className="vidya-role-tag"
                style={{ background: current.examBg, color: current.color }}>{current.role}</span>
              <div className="vidya-subject-chips">
                {current.subjects.map(s => <span key={s} className="vidya-chip">{s}</span>)}
              </div>
            </div>
          </div>

          <div className="vidya-divider" />
          <div className="vidya-section-label">CHOOSE YOUR TEACHER</div>

          {/* Teacher grid */}
          <div className="vidya-teacher-grid">
            {Object.values(TEACHERS).map(t => (
              <div key={t.id}
                className={`vidya-t-card ${current.id === t.id ? "active" : ""}`}
                style={current.id === t.id ? { borderColor: t.color, background: `rgba(${t.colorRGB},0.07)` } : {}}
                onClick={() => selectTeacher(t.id)}>
                <div className="vidya-t-icon">{t.icon}</div>
                <div className="vidya-t-name">{t.name}</div>
                <div className="vidya-t-sub">{t.subjects[0]}</div>
              </div>
            ))}
          </div>

          <div className="vidya-divider" />

          {/* Quick questions */}
          <div className="vidya-qt-wrap">
            <div className="vidya-qt-label">Quick Questions</div>
            {current.quickTopics.map(q => (
              <button key={q} className="vidya-qt-btn" onClick={() => sendMessage(q)}>
                💬 {q}
              </button>
            ))}
          </div>

          {/* Voice toggle */}
          <div className="vidya-voice-wrap">
            <button
              className={`vidya-voice-btn ${autoVoice ? "on" : ""}`}
              style={autoVoice ? { borderColor: current.color, color: current.color } : {}}
              onClick={() => setAutoVoice(v => !v)}>
              {autoVoice ? "🔊  Auto-Speak: ON" : "🔇  Auto-Speak: OFF"}
            </button>
          </div>

          {/* Change API Key */}
          {apiKey && (
            <div className="vidya-voice-wrap">
              <button className="vidya-voice-btn"
                onClick={() => { setShowKeyPrompt(true); setApiKey(""); localStorage.removeItem("vidya_gemini_key"); }}>
                🔑 Change API Key
              </button>
            </div>
          )}
        </aside>

        {/* ── Chat main ── */}
        <main className="vidya-chat-main">

          {/* Header */}
          <div className="vidya-chat-header">
            <div>
              <div className="vidya-chat-header-name">{current.fullName}</div>
              <div className="vidya-status-dot">
                {apiKey ? "Online · Ready to teach" : "⚠️ API key needed"}
              </div>
            </div>
            <div className="vidya-exam-ind"
              style={{ background: current.examBg, color: current.color, border: `1px solid ${current.examBorder}` }}>
              {current.exam}
            </div>
          </div>

          {/* Messages */}
          <div className="vidya-chatbox" ref={chatboxRef}>
            <div className="vidya-welcome-card" style={{ borderColor: `rgba(${current.colorRGB},0.18)`, background: `linear-gradient(135deg,rgba(${current.colorRGB},0.07),rgba(0,0,0,0.2))` }}>
              <h3>🎯 Preparing for {current.exam}</h3>
              <p>Ask me anything — concepts, solved examples, shortcuts, or exam strategy. I teach from NCERT and top reference books used in India.</p>
              <div className="vidya-w-tags">
                {current.subjects.map(s => <span key={s} className="vidya-w-tag">📚 {s}</span>)}
                <span className="vidya-w-tag">📖 NCERT Based</span>
                <span className="vidya-w-tag">✅ Exam Focused</span>
              </div>
            </div>

            {messages.map(msg => (
              <div key={msg.id}
                className={`vidya-msg ${msg.role === "user" ? "user" : "bot"}`}
                style={msg.role === "user" ? { background: `linear-gradient(135deg,${current.color},${current.color}cc)` } : {}}>
                {msg.text}
              </div>
            ))}

            {busy && (
              <div className="vidya-msg bot vidya-typing">
                <span /><span /><span />
              </div>
            )}
          </div>

          {/* Input */}
          <div className="vidya-input-area">
            <input
              ref={inputRef}
              className="vidya-input"
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={e => { if (e.key === "Enter") { e.preventDefault(); sendMessage(); } }}
              placeholder={apiKey ? "Ask your NEET / JEE doubt here…" : "Enter API key to start chatting…"}
              style={{ "--focus-color": current.color }}
              disabled={!apiKey}
            />
            <button
              className="vidya-send-btn"
              style={{ background: `linear-gradient(135deg,${current.color},${current.color}bb)` }}
              onClick={() => sendMessage()}
              disabled={busy || !apiKey}>
              <svg viewBox="0 0 24 24" width="17" height="17" fill="#000">
                <path d="M2.01 21L23 12 2.01 3 2 10l15 2-15 2z" />
              </svg>
            </button>
          </div>
        </main>
      </div>
    </PageLayout>
  );
}
